const amqp = require('amqplib');

async function main() {
  // Connect to RabbitMQ server
  const connection = await amqp.connect('amqp://localhost');
  const channel = await connection.createChannel();

  // Declare the queue and bind it to the payment exchange
  const queue = await channel.assertQueue('payment_queue', { durable: true });
  const exchange = await channel.assertExchange('payment_exchange', 'topic');
  await channel.bindQueue(queue, exchange, 'payment.*');

  // Start consuming messages from the queue
  console.log('Waiting for payment events...');
  await channel.consume(queue, async message => {
    try {
      // Process the message content and execute payment logic directly based on message content
      const msgContent = JSON.parse(message.content);
      if (msgContent.event === 'payment_succeeded') {
        console.log(`Payment succeeded for order ${msgContent.orderId}`);
        // TODO: Implement payment logic for successful payments
      } else if (msgContent.event === 'payment_failed') {
        console.log(`Payment failed for order ${msgContent.orderId}`);
        // TODO: Implement payment logic for failed payments
      } else {
        console.error('Unrecognized message event', msgContent.event);
      }
    } catch (err) {
      console.error(err);
    } finally {
      channel.ack(message);
    }
  });
}